const input = $input.first().json;

const text =
  input.text ||
  input.data ||
  input.content ||
  input.extractedText ||
  "";

if (!text || text.trim().length === 0) {
  throw new Error("No text found from PDF extraction. Use a text-based PDF, not scanned image PDF.");
}

const chunkSize = 1200;
const overlap = 150;

const cleanText = text
  .replace(/\r/g, "\n")
  .replace(/\n{3,}/g, "\n\n")
  .replace(/[ \t]+/g, " ")
  .trim();

const chunks = [];
let start = 0;
let chunkIndex = 1;

const fileName =
  $input.first().binary?.file?.fileName ||
  "uploaded.pdf";

while (start < cleanText.length) {
  const end = Math.min(start + chunkSize, cleanText.length);
  const chunkText = cleanText.slice(start, end).trim();

  if (chunkText.length > 50) {
    chunks.push({
      json: {
        chunk_id: `${Date.now()}_chunk_${chunkIndex}`,
        chunk_number: chunkIndex,
        text: chunkText,
        characters: chunkText.length,
        source_file_name: fileName,
        created_at: new Date().toISOString()
      }
    });
  }

  chunkIndex++;
  start += chunkSize - overlap;
}

return chunks;

const original = $('Chunk PDF Text').item.json;
const embeddingResponse = $json;

const embedding = embeddingResponse.embeddings?.[0];

if (!embedding || !Array.isArray(embedding)) {
  throw new Error("No embedding returned from Ollama.");
}

return {
  json: {
    id: original.chunk_id,
    document: original.text,
    embedding,
    metadata: {
      chunk_number: original.chunk_number,
      source_file_name: original.source_file_name,
      characters: original.characters,
      created_at: original.created_at
    }
  }
};

const items = $input.all();

return [
  {
    json: {
      ids: items.map(item => item.json.id),
      documents: items.map(item => item.json.document),
      embeddings: items.map(item => item.json.embedding),
      metadatas: items.map(item => item.json.metadata)
    }
  }
];

return {
  json: {
    ids: $json.ids,
    documents: $json.documents,
    embeddings: $json.embeddings,
    metadatas: $json.metadatas
  }
};

const question = $json.body?.question || $json.question;

if (!question || question.trim().length === 0) {
  throw new Error('Missing question. Send JSON body: {"question":"your question"}');
}

return {
  json: {
    question: question.trim()
  }
};

const question = $('Validate Question').item.json.question;
const embedding = $json.embeddings?.[0];

if (!embedding || !Array.isArray(embedding)) {
  throw new Error("No question embedding returned from Ollama.");
}

return {
  json: {
    question,
    embedding,
    n_results: 5
  }
};

const question = $('Prepare Chroma Query').item.json.question;

const docs = $json.documents?.[0] || [];
const ids = $json.ids?.[0] || [];
const metadatas = $json.metadatas?.[0] || [];
const distances = $json.distances?.[0] || [];

if (!docs.length) {
  return {
    json: {
      question,
      prompt: `
You are a professional document intelligence assistant.

No relevant document passages were retrieved.

User question:
${question}

Return a polished answer saying that the uploaded document does not contain enough evidence to answer confidently.
Do not invent information.
`,
      sources: []
    }
  };
}

const sources = docs.map((doc, index) => ({
  source_number: index + 1,
  chunk_id: ids[index] || `source_${index + 1}`,
  text: doc,
  metadata: metadatas[index] || {},
  distance: distances[index]
}));

const contextText = sources.map(source => {
  return `REFERENCE ${source.source_number}
File: ${source.metadata?.source_file_name || "uploaded.pdf"}
Passage:
${source.text}`;
}).join("\n\n---\n\n");

const prompt = `
You are a senior AI document analyst.

Your task:
Answer the user's question using ONLY the retrieved document passages.

Important behavior:
- Give the most useful answer possible from the available passages.
- Do not begin with phrases like "Based on the provided sources" or "Unfortunately".
- Do not expose chunk numbers, internal IDs, embeddings, or similarity scores.
- Use citations like [1], [2], [3] after claims.
- If the document only partially answers the question, say that calmly under "Limitations".
- If the user asks for skills, steps, ideas, or strategy, extract implied skills and practical takeaways from the references instead of saying "not found" too quickly.
- Keep the tone polished, concise, and recruiter-friendly.

Output exactly in this format:

### Answer
Give a direct answer in 2–4 short paragraphs.

### Key takeaways
- Takeaway 1 [1]
- Takeaway 2 [2]
- Takeaway 3 [3]

### Confidence
High / Medium / Low — explain in one sentence.

### References used
[1] Briefly explain what reference 1 supports.
[2] Briefly explain what reference 2 supports.
[3] Briefly explain what reference 3 supports.

User question:
${question}

Retrieved document passages:
${contextText}
`;

return {
  json: {
    question,
    prompt,
    sources
  }
};

