const ollamaOutput = $json;

const answer =
  ollamaOutput.message?.content ||
  ollamaOutput.response ||
  ollamaOutput.content ||
  "No answer generated.";

const question = $('Build Answer Prompt').item.json.question;
const sources = $('Build Answer Prompt').item.json.sources || [];

function cleanSnippet(text, maxLength = 520) {
  if (!text) return "";
  const clean = String(text)
    .replace(/\s+/g, " ")
    .replace(/www\.[^\s]+/g, "")
    .trim();

  return clean.length > maxLength ? clean.slice(0, maxLength) + "..." : clean;
}

return {
  json: {
    question,
    answer,
    references: sources.map(source => ({
      reference_number: source.source_number,
      title: `Reference ${source.source_number}`,
      file_name: source.metadata?.source_file_name || "uploaded.pdf",
      snippet: cleanSnippet(source.text)
    })),
    debug_sources: sources.map(source => ({
      source_number: source.source_number,
      chunk_id: source.chunk_id,
      chunk_number: source.metadata?.chunk_number,
      source_file_name: source.metadata?.source_file_name,
      similarity_distance: source.distance
    }))
  }
};

const question = $json.question;
const embedding = $json.embedding;
const n_results = 5;

if (!embedding || !Array.isArray(embedding)) {
  throw new Error("Embedding is missing or not an array.");
}

return {
  json: {
    question,
    embedding,
    n_results
  }
};
